```javascript
const { Client, Intents, GatewayIntentBits } = require('discord.js');
const { REST, Routes } = require('discord.js');
const { token, clientId, guildId } = require('./config.json');

const client = new Client({
    intents: [
        GatewayIntentBits.Guilds,
        GatewayIntentBits.GuildBans,
        GatewayIntentBits.GuildMembers,
        GatewayIntentBits.MessageContent,
    ]
});

client.once('ready', () => {
    console.log('Bot is online!');
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isCommand()) return;

    const { commandName } = interaction;

    if (commandName === 'ban') {
        if (!interaction.member.permissions.has('BAN_MEMBERS')) {
            await interaction.reply("You don't have permission to ban members.");
            return;
        }

        const user = interaction.options.getUser('user');
        const reason = interaction.options.getString('reason', true) || 'No reason provided.';

        if (!user) {
            await interaction.reply("You didn't mention a user to ban.");
            return;
        }

        const member = interaction.guild.members.resolve(user);
        if (!member) {
            await interaction.reply("That user isn't in this guild.");
            return;
        }

        member
            .ban({ reason: reason })
            .then(() => {
                await interaction.reply(`Successfully banned ${user.tag} for: ${reason}`);
            })
            .catch(err => {
                console.error(err);
                await interaction.reply("I was unable to ban the member.");
            });
    }
});

const commands = [
    {
        name: 'ban',
        description: 'Ban a user from the server',
        options: [
            {
                name: 'user',
                type: 'USER',
                description: 'The user to ban',
                required: true,
            },
            {
                name: 'reason',
                type: 'STRING',
                description: 'Reason for banning',
                required: true,
            }
        ],
    }
];

const rest = new REST({ version: '9' }).setToken(token);
(async () => {
    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(
            Routes.applicationGuildCommands(clientId, guildId),
            { body: commands },
        );

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
})();

client.login(token);
```

