#include <iostream>
#include <string>
#include <sstream>

std::string markdownToHTML(const std::string& markdown) {
    std::stringstream ss;

    // Convert headings
    const std::string headingPattern = "^(#{1,6})\\s+(.*)$";
    std::regex headingRegex(headingPattern);
    auto pos = markdown.cbegin();
    std::smatch match;
    while (std::regex_search(pos, markdown.cend(), match, headingRegex)) {
        size_t level = match[1].length() - 1;
        ss << "<h" << level << ">" << match[2] << "</h" << level << ">\n";
        pos = match.suffix().first;
    }

    // Convert bold and italic text
    std::string boldPattern = "\\*\\*(.*?)\\*\\*";
    std::string italicPattern = "\\*(.*?)\\*";
    std::regex boldRegex(boldPattern);
    std::regex italicRegex(italicPattern);
    pos = markdown.cbegin();
    while (std::regex_search(pos, markdown.cend(), match, boldRegex) ||
           std::regex_search(pos, markdown.cend(), match, italicRegex)) {
        if (std::regex_search(pos, markdown.cend(), match, boldRegex)) {
            ss << "<strong>" << match[1] << "</strong>";
        } else if (std::regex_search(pos, markdown.cend(), match, italicRegex)) {
            ss << "<em>" << match[1] << "</em>";
        }
        pos = match.suffix().first;
    }

    // Insert remaining text
    ss << markdown.substr(pos - markdown.begin());

    return ss.str();
}

int main() {
    std::string markdown = R"(
# Heading 1
## Heading 2
### Heading 3

*Italic text* and **bold text**.

- List item 1
- List item 2
)";
    std::string html = markdownToHTML(markdown);
    std::cout << html << std::endl;
    return 0;
}
```

